class ApplyPending(EventPermissionRequired, TemplateView):
    permission_required = "orga.change_submissions"
    template_name = "orga/submission/apply_pending.html"

    @cached_property
    def submissions(self):
        return self.request.event.submissions.filter(pending_state__isnull=False)

    @context
    @cached_property
    def submission_count(self):
        return len(self.submissions)

    def post(self, request, *args, **kwargs):
        for submission in self.submissions:
            try:
                submission.apply_pending_state(person=self.request.user)
            except Exception:
                submission.apply_pending_state(person=self.request.user, force=True)
        messages.success(
            self.request,
            str(_("Changed {count} proposal states.")).format(
                count=self.submission_count
            ),
        )
        url = self.request.GET.get("next")
        if url and url_has_allowed_host_and_scheme(url, allowed_hosts=None):
            return redirect(url)
        return redirect(self.request.event.orga_urls.submissions)

    @context
    def next(self):
        return self.request.GET.get("next")

from django.conf import settings
from django.core.serializers.json import DjangoJSONEncoder
from django.db import models
from django.utils.translation import gettext_lazy as _

from legal_advice_builder.utils import clean_html_field
from legal_advice_builder.utils import get_answer_from_list

from .law_case import LawCase
from .question import Question


class Answer(models.Model):
    law_case = models.ForeignKey(LawCase, on_delete=models.CASCADE)
    created_at = models.DateTimeField(auto_now_add=True)
    updated_at = models.DateTimeField(auto_now=True)
    creator = models.ForeignKey(settings.AUTH_USER_MODEL, blank=True,
                                null=True, on_delete=models.SET_NULL)
    answers = models.JSONField(null=True, default=dict, blank=True, encoder=DjangoJSONEncoder)
    rendered_document = models.TextField(blank=True, verbose_name=_('Rendered Document'))
    extra_info = models.JSONField(default=dict, blank=True, null=True)
    external_id = models.IntegerField(blank=True, null=True)

    def __str__(self):
        date = str(self.created_at.date())
        return '{} {} ({})'.format(date, self.law_case.title, self.creator)

    def save(self, *args, **kwargs):
        self.rendered_document = clean_html_field(self.rendered_document)
        return super().save(*args, **kwargs)

    def save_rendered_document(self):
        if not self.rendered_document:
            self.rendered_document = self.template
            self.save()

    @property
    def template(self):
        return self.law_case.document.template_with_answers(self.answers)

    def get_answer_for_question(self, question_short_title):
        questions = Question.objects.filter(
            questionaire__law_case=self.law_case)
        question = questions.filter(
            short_title=question_short_title)
        if question:
            return get_answer_from_list(self.answers, question.first())

from django.conf import settings
from django.contrib.auth.decorators import login_required
from django.contrib.auth.mixins import LoginRequiredMixin, PermissionRequiredMixin
from django.core.exceptions import PermissionDenied
from django.db import IntegrityError
from django.forms.models import ModelForm
from django.http import Http404, HttpResponse, HttpResponseBadRequest, HttpResponseForbidden, HttpResponseNotFound
from django.shortcuts import get_object_or_404
from django.utils.translation import gettext as _
from django.views.decorators.http import require_POST
from django.views.generic import DetailView, UpdateView
from reversion import revisions
from reversion.models import Version

from judge.dblock import LockModel
from judge.models import Comment, CommentVote
from judge.utils.views import TitleMixin
from judge.widgets import MathJaxPagedownWidget

__all__ = ['upvote_comment', 'downvote_comment', 'CommentEditAjax', 'CommentContent',
           'CommentEdit']


@login_required
def vote_comment(request, delta):
    if abs(delta) != 1:
        return HttpResponseBadRequest(_('Messing around, are we?'), content_type='text/plain')

    if request.method != 'POST':
        return HttpResponseForbidden()

    if 'id' not in request.POST or len(request.POST['id']) > 10:
        return HttpResponseBadRequest()

    if request.profile.is_new_user:
        return HttpResponseBadRequest(_('You must solve at least %d problems before you can vote.')
                                      % settings.VNOJ_INTERACT_MIN_PROBLEM_COUNT,
                                      content_type='text/plain')

    if request.profile.mute:
        suffix_msg = '' if request.profile.ban_reason is None else _(' Reason: ') + request.profile.ban_reason
        return HttpResponseBadRequest(_('Your part is silent, little toad.') + suffix_msg, content_type='text/plain')

    try:
        comment_id = int(request.POST['id'])
    except ValueError:
        return HttpResponseBadRequest()

    comment = Comment.objects.filter(id=comment_id, hidden=False).first()

    if not comment:
        return HttpResponseNotFound(_('Comment not found.'), content_type='text/plain')

    if comment.author == request.profile:
        return HttpResponseBadRequest(_('You cannot vote on your own comments.'), content_type='text/plain')

    vote = CommentVote()
    vote.comment_id = comment_id
    vote.voter = request.profile
    vote.score = delta

    while True:
        try:
            vote.save()
        except IntegrityError:
            with LockModel(write=(CommentVote,)):
                try:
                    vote = CommentVote.objects.get(comment_id=comment_id, voter=request.profile)
                except CommentVote.DoesNotExist:
                    # We must continue racing in case this is exploited to manipulate votes.
                    continue
                return HttpResponseBadRequest(_('You cannot vote twice.'), content_type='text/plain')
        else:
            Comment.objects.get(id=comment_id).vote(delta)
        break
    return HttpResponse('success', content_type='text/plain')


def upvote_comment(request):
    return vote_comment(request, 1)


def downvote_comment(request):
    return vote_comment(request, -1)


class CommentMixin(object):
    model = Comment
    pk_url_kwarg = 'id'
    context_object_name = 'comment'

    def get_object(self, queryset=None):
        comment = super().get_object(queryset)
        if not comment.is_accessible_by(self.request.user):
            raise Http404()
        return comment


class CommentRevisionAjax(CommentMixin, DetailView):
    template_name = 'comments/revision-ajax.html'

    def get_context_data(self, **kwargs):
        context = super(CommentRevisionAjax, self).get_context_data(**kwargs)
        revisions = Version.objects.get_for_object(self.object).order_by('-revision')
        try:
            wanted = min(max(int(self.request.GET.get('revision', 0)), 0), len(revisions) - 1)
        except ValueError:
            raise Http404
        context['revision'] = revisions[wanted]
        return context

    def get_object(self, queryset=None):
        comment = super(CommentRevisionAjax, self).get_object(queryset)
        if comment.hidden and not self.request.user.has_perm('judge.change_comment'):
            raise Http404()
        return comment


class CommentEditForm(ModelForm):
    class Meta:
        model = Comment
        fields = ['body']
        if MathJaxPagedownWidget is not None:
            widgets = {'body': MathJaxPagedownWidget(attrs={'id': 'id-edit-comment-body'})}


class CommentEditAjax(LoginRequiredMixin, CommentMixin, UpdateView):
    template_name = 'comments/edit-ajax.html'
    form_class = CommentEditForm

    def form_valid(self, form):
        with revisions.create_revision(atomic=True):
            revisions.set_comment(_('Edited from site'))
            revisions.set_user(self.request.user)
            return super(CommentEditAjax, self).form_valid(form)

    def get_success_url(self):
        return self.object.get_absolute_url()

    def get_object(self, queryset=None):
        comment = super(CommentEditAjax, self).get_object(queryset)
        if self.request.user.has_perm('judge.change_comment'):
            return comment
        profile = self.request.profile
        if profile != comment.author or profile.mute or comment.hidden:
            raise Http404()
        return comment


class CommentEdit(TitleMixin, CommentEditAjax):
    template_name = 'comments/edit.html'

    def get_title(self):
        return _('Editing comment')


class CommentContent(CommentMixin, DetailView):
    template_name = 'comments/content.html'


class CommentVotesAjax(PermissionRequiredMixin, CommentMixin, DetailView):
    template_name = 'comments/votes.html'
    permission_required = 'judge.change_comment'

    def get_context_data(self, **kwargs):
        context = super(CommentVotesAjax, self).get_context_data(**kwargs)
        context['votes'] = (self.object.votes.select_related('voter__user')
                            .only('id', 'voter__display_rank', 'voter__user__username', 'score'))
        return context


@require_POST
def comment_hide(request):
    if not request.user.has_perm('judge.change_comment'):
        raise PermissionDenied()
    try:
        comment_id = int(request.POST['id'])
    except ValueError:
        return HttpResponseBadRequest()

    comment = get_object_or_404(Comment, id=comment_id)
    comment.get_descendants(include_self=True).update(hidden=True)
    comment.author.calculate_contribution_points()
    return HttpResponse('ok')

