from django.core.exceptions import ValidationError
from django.db import models
from django.utils.translation import gettext_lazy as _
from .partnership import Partnership

from ..fields import ValidXMLCharField


class PublishingStatus(models.Model):
    """Keep track of publishing status."""
    STATUS_PUBLISHED = 'published'
    STATUS_UNPUBLISHED = 'unpublished'
    PUBLISHING_STATUS = (
        (STATUS_UNPUBLISHED, _('Unpublished')),
        (STATUS_PUBLISHED, _('Published')),
    )

    project = models.OneToOneField('Project', on_delete=models.CASCADE,)
    status = ValidXMLCharField(max_length=30,
                               choices=PUBLISHING_STATUS,
                               db_index=True, default=STATUS_UNPUBLISHED)

    def clean(self):
        """Projects can only be published, when several checks have been performed."""
        if self.status == 'published':
            validation_errors = []

            if not self.project.title:
                validation_errors.append(
                    ValidationError(_('Project needs to have a title.'),
                                    code='title')
                )

            if not self.project.subtitle:
                validation_errors.append(
                    ValidationError(_('Project needs to have a subtitle.'),
                                    code='subtitle')
                )

            if self.project.iati_status == '6':
                validation_errors.append(
                    ValidationError(_('Project needs to have non-suspended status.'),
                                    code='status')
                )

            if not (self.project.date_start_planned or self.project.date_start_actual):
                validation_errors.append(
                    ValidationError(
                        _('Project needs to have the planned or actual start date field filled '
                          'in.'), code='start_date')
                )

            if not self.project.current_image:
                validation_errors.append(
                    ValidationError(_('Project needs to have a photo.'),
                                    code='current_image')
                )

            if not self.project.partnerships.filter(
                    organisation__can_create_projects__exact=True).exists():
                validation_errors.append(
                    ValidationError(
                        _('Project has no partner that is allowed to publish it.'),
                        code='partners'
                    )
                )

            if not self.project.partnerships.filter(
                    iati_organisation_role__in=[Partnership.IATI_FUNDING_PARTNER,
                                                Partnership.IATI_IMPLEMENTING_PARTNER,
                                                Partnership.IATI_ACCOUNTABLE_PARTNER]
            ).exists():
                validation_errors.append(
                    ValidationError(
                        _('Project needs to have at least one funding, implementing or accountable '
                          'partner.'),
                        code='partners'
                    )
                )
            else:
                for funding_partner in self.project.partnerships.filter(
                        iati_organisation_role=Partnership.IATI_FUNDING_PARTNER):
                    if not funding_partner.funding_amount and not funding_partner.funding_amount == 0:
                        validation_errors.append(
                            ValidationError(_('All funding partners should have a funding amount.'),
                                            code='partners'
                                            )
                        )
                        break

            if not self.project.project_plan_summary:
                validation_errors.append(
                    ValidationError(_('Project needs to have the project plan summary filled in.'),
                                    code='summary')
                )

            if not self.project.goals_overview:
                validation_errors.append(
                    ValidationError(_('Project needs to have the goals overview field filled in.'),
                                    code='goals_overview')
                )

            if not self.project.locations.all():
                validation_errors.append(
                    ValidationError(_('Project needs to have at least one location.'),
                                    code='location')
                )
            else:
                for location in self.project.locations.all():
                    if not (location.latitude and location.longitude):
                        validation_errors.append(
                            ValidationError(
                                _('All locations need to have a latitude and longitude specified.'),
                                code='location')
                        )
                        break

            if not self.project.budget_items.all():
                validation_errors.append(
                    ValidationError(_('Project needs to have at least one budget item.'),
                                    code='budget_item')
                )
            elif not self.project.budget_items.filter(amount__gte=0).exists():
                validation_errors.append(
                    ValidationError(
                        _('Project needs to have at least one budget item with an amount.'),
                        code='budget_item'
                    )
                )

            if validation_errors:
                raise ValidationError(validation_errors)

    class Meta:
        app_label = 'rsr'
        verbose_name = _('publishing status')
        verbose_name_plural = _('publishing statuses')
        ordering = ('-status', 'project')

from django.contrib.auth.models import BaseUserManager
from django.utils.translation import gettext as _


class CustomUserManager(BaseUserManager):
    def create_user(self, username, email, password=None, **extra_fields):
        if not email:
            raise ValueError(_('Users must provide an email address'))
        if not username:
            raise ValueError(_('Users must provide a username'))
        if not extra_fields.get("first_name"):
            raise ValueError(_('Users must provide a first name'))
        if not extra_fields.get("last_name"):
            raise ValueError(_('Users must provide a last name'))

        email = self.normalize_email(email)

        # Pop fields to avoid passing them twice
        first_name = extra_fields.pop("first_name")
        last_name = extra_fields.pop("last_name")

        user = self.model(
            username=username,
            email=email,
            first_name=first_name,
            last_name=last_name,
            **extra_fields
        )
        user.set_password(password)
        user.save(using=self._db)
        return user

    def create_superuser(self, username, email, password, **extra_fields):
        extra_fields.setdefault('is_staff', True)
        extra_fields.setdefault('is_superuser', True)
        extra_fields.setdefault('is_active', True)

        if extra_fields.get('is_staff') is not True:
            raise ValueError(_('Superuser must have is_staff=True.'))
        if extra_fields.get('is_superuser') is not True:
            raise ValueError(_('Superuser must have is_superuser=True.'))

        return self.create_user(username, email, password, **extra_fields)

import logging

from gaphor import UML
from gaphor.core import gettext
from gaphor.core.modeling.properties import attribute
from gaphor.core.styling import FontStyle, FontWeight, VerticalAlign
from gaphor.diagram.presentation import (
    Classified,
    ElementPresentation,
    from_package_str,
)
from gaphor.diagram.shapes import Box, Text, draw_border
from gaphor.diagram.support import represents
from gaphor.SysML import sysml
from gaphor.UML.classes.klass import (
    attribute_watches,
    attributes_compartment,
    operation_watches,
    operations_compartment,
)
from gaphor.UML.classes.stereotype import stereotype_compartments, stereotype_watches

log = logging.getLogger(__name__)


@represents(UML.DataType)
@represents(UML.PrimitiveType)
@represents(sysml.ValueType)
class DataTypeItem(Classified, ElementPresentation[UML.DataType]):
    """This item visualizes a Data Type instance.

    A DataTypeItem contains two compartments:
    1. Attributes
    2. Operations
    """

    def __init__(self, diagram, id=None):
        super().__init__(diagram, id=id)

        self.watch("show_attributes", self.update_shapes).watch(
            "show_operations", self.update_shapes
        ).watch("subject[NamedElement].name").watch(
            "subject[NamedElement].namespace.name"
        )
        attribute_watches(self, "DataType")
        operation_watches(self, "DataType")
        stereotype_watches(self)

    show_stereotypes: attribute[int] = attribute("show_stereotypes", int)

    show_attributes: attribute[int] = attribute("show_attributes", int, default=True)

    show_operations: attribute[int] = attribute("show_operations", int, default=True)

    def additional_stereotypes(self):
        if isinstance(self.subject, UML.PrimitiveType):
            return [gettext("primitive")]
        elif isinstance(self.subject, sysml.ValueType):
            return [gettext("valueType")]
        elif isinstance(self.subject, UML.DataType):
            return [gettext("dataType")]
        else:
            return ()

    def update_shapes(self, event=None):
        self.shape = Box(
            Box(
                Text(
                    text=lambda: UML.recipes.stereotypes_str(
                        self.subject, self.additional_stereotypes()
                    ),
                ),
                Text(
                    text=lambda: self.subject.name or "",
                    style={
                        "font-weight": FontWeight.BOLD,
                        "font-style": FontStyle.ITALIC
                        if self.subject and self.subject.isAbstract
                        else FontStyle.NORMAL,
                    },
                ),
                Text(
                    text=lambda: from_package_str(self),
                    style={"font-size": "x-small"},
                ),
                style={"padding": (12, 4, 12, 4)},
            ),
            *(
                self.show_attributes
                and self.subject
                and [attributes_compartment(self.subject)]
                or []
            ),
            *(
                self.show_operations
                and self.subject
                and [operations_compartment(self.subject)]
                or []
            ),
            *(self.show_stereotypes and stereotype_compartments(self.subject) or []),
            style={
                "vertical-align": VerticalAlign.TOP,
            },
            draw=draw_border,
        )

from django.shortcuts import render, get_object_or_404, redirect
