        elif promo_type == "late_promo":
            product_name = "Mummy Day Care - Promoção (até 12 de maio)"
        else:
            product_name = "Mummy Day Care - Preço Regular"

        session_data = {
            'payment_method_types': ['card'],
            'line_items': [
                {
                    'price_data': {
                        'currency': 'eur',
                        'product_data': {
                            'name': product_name,
