    def post(self, request, *args, **kwargs):
        request.session["harbor_user_modal"] = True
        return HttpResponse(status=204)

# The full rewrite will include updated models for flexible plan options with multilingual pricing,
# automatic nutrition range aggregation, and view adjustments. Let's start with mealplans/models.py

from django.db import models
from django.utils.translation import gettext_lazy as _
from meals.models import Meal

MEAL_TIME_CHOICES = [
    ('breakfast', _('Breakfast')),
    ('lunch', _('Lunch')),
    ('dinner', _('Dinner')),
]

DURATION_CHOICES = [
    (7,  _('1 Week')),
    (14, _('2 Weeks')),
    (21, _('3 Weeks')),
    (28, _('4 Weeks')),
]

class Goal(models.Model):
    name = models.CharField(max_length=100, unique=True)
    description = models.TextField(blank=True)

    def __str__(self):
        return self.name

class ExcludableItem(models.Model):
    name = models.CharField(max_length=100, unique=True)
    description = models.TextField(blank=True)

    def __str__(self):
        return self.name

class MealPlanExtra(models.Model):
    name = models.CharField(max_length=100)
    price_per_week = models.DecimalField(max_digits=6, decimal_places=2)
    description = models.TextField(blank=True)

    def __str__(self):
        return f"{self.name} (+{self.price_per_week})"

class MealPlan(models.Model):
    name = models.CharField(max_length=100)
    goal = models.ForeignKey(Goal, on_delete=models.CASCADE, related_name='mealplans')
    description = models.TextField(blank=True)
    benefits = models.TextField(blank=True)
    contraindications = models.TextField(blank=True)
    is_active = models.BooleanField(default=True)
    image = models.ImageField(upload_to='mealplans/', blank=True, null=True)
    excludable_items = models.ManyToManyField(ExcludableItem, blank=True)
    extras = models.ManyToManyField(MealPlanExtra, blank=True)

    def __str__(self):
        return self.name

    def get_nutrition_range(self):
        min_vals = {'calories': 0, 'protein': 0, 'carbs': 0, 'fat': 0, 'fiber': 0}
        max_vals = {'calories': 0, 'protein': 0, 'carbs': 0, 'fat': 0, 'fiber': 0}
        all_meals = Meal.objects.filter(mealplandaymeal__day__plan=self).distinct()
        if not all_meals.exists():
            return None
        nutrition_list = [meal.total_nutrition() for meal in all_meals]
        for key in min_vals:
            values = [n[key] for n in nutrition_list]
            min_vals[key] = round(min(values), 2)
            max_vals[key] = round(max(values), 2)
        return {'min': min_vals, 'max': max_vals}

class MealPlanPackageOption(models.Model):
    plan = models.ForeignKey(MealPlan, on_delete=models.CASCADE, related_name='package_options')
    name = models.CharField(max_length=50)  # e.g., "Lunch Only"
    meals_included = models.CharField(max_length=100)  # comma-separated: "lunch", "lunch,dinner"
    price = models.DecimalField(max_digits=8, decimal_places=2)


    def __str__(self):
        return f"{self.plan.name} - {self.name}"

    def get_price_by_lang(self, lang):
        return getattr(self, f"price_{lang}", self.price)

class MealPlanDay(models.Model):
    plan = models.ForeignKey(MealPlan, on_delete=models.CASCADE, related_name='days')
    day_number = models.PositiveIntegerField()  # 1-28
    is_sunday = models.BooleanField(default=False)

    class Meta:
        unique_together = ('plan', 'day_number')
        ordering = ['day_number']

    def __str__(self):
        return f"{self.plan.name} - Day {self.day_number}"

class MealPlanDayMeal(models.Model):
    day = models.ForeignKey(MealPlanDay, on_delete=models.CASCADE, related_name='meals')
    meal_time = models.CharField(max_length=20, choices=MEAL_TIME_CHOICES)
    meal = models.ForeignKey(Meal, on_delete=models.CASCADE)

    class Meta:
        unique_together = ('day', 'meal_time')

    def __str__(self):
        return f"{self.day} - {self.get_meal_time_display()}: {self.meal.name}"

    def get_meal_time_display(self):
        return dict(MEAL_TIME_CHOICES).get(self.meal_time, self.meal_time)

