    # )
    # return ''.join(re.findall('(?<=>>> Invoking Beeline command line now >>>)
    # (.*?)(?=<<< Invocation of Beeline command completed <<<)', logs['stdout'], re.DOTALL))
    return ''

  def get_jobs(self, notebook, snippet, logs):
    # 50cf0e00-746b-4d86-b8e3-f2722296df71
